using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// MCP tools that wrap a weather REST API.
/// The MCP SDK discovers tools by scanning for [McpServerToolType] classes
/// and [McpServerTool] methods. Constructor parameters are resolved from DI.
/// </summary>
[McpServerToolType]
public class WeatherTools
{
    private readonly HttpClient _httpClient;

    // The SDK instantiates this class per-call, injecting services from DI.
    public WeatherTools(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [McpServerTool, Description("Get the current weather forecast for a US state.")]
    public async Task<string> GetForecast(
        [Description("Two-letter US state code, e.g. CA")] string state,
        CancellationToken cancellationToken = default)
    {
        // NWS API requires a grid point; use state capital coordinates as a demo.
        var coordinates = GetStateCoordinates(state.ToUpperInvariant());

        var pointUrl = $"https://api.weather.gov/points/{coordinates.lat},{coordinates.lon}";
        var pointResponse = await _httpClient.GetFromJsonAsync<JsonElement>(pointUrl, cancellationToken);
        var forecastUrl = pointResponse.GetProperty("properties").GetProperty("forecast").GetString()
            ?? throw new InvalidOperationException("No forecast URL returned");

        var forecast = await _httpClient.GetFromJsonAsync<JsonElement>(forecastUrl, cancellationToken);
        var periods = forecast.GetProperty("properties").GetProperty("periods");

        // Return the first two periods (today + tonight).
        var results = periods.EnumerateArray()
            .Take(2)
            .Select(p => $"{p.GetProperty("name")}: {p.GetProperty("detailedForecast")}");

        return string.Join("\n\n", results);
    }

    [McpServerTool, Description("List all weather alerts for a US state.")]
    public async Task<string> GetAlerts(
        [Description("Two-letter US state code, e.g. TX")] string state,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.weather.gov/alerts/active?area={state.ToUpperInvariant()}";
        var response = await _httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);

        var features = response.GetProperty("features");
        if (features.GetArrayLength() == 0)
            return $"No active alerts for {state.ToUpperInvariant()}.";

        var alerts = features.EnumerateArray()
            .Take(5)
            .Select(f =>
            {
                var props = f.GetProperty("properties");
                return $"[{props.GetProperty("severity")}] {props.GetProperty("headline")}";
            });

        return string.Join("\n", alerts);
    }

    private static (double lat, double lon) GetStateCoordinates(string state) => state switch
    {
        "CA" => (38.5816, -121.4944),
        "TX" => (30.2672, -97.7431),
        "NY" => (42.6526, -73.7562),
        "FL" => (30.4383, -84.2807),
        _ => (38.8977, -77.0365), // default to DC
    };
}

